"  const handleRequestDiscTest = async (appId: string, currentPhone: string) => {
    try {
      const originalPhone = (currentPhone || '').split('===DISC===')[0].trim();
      const updatedPhoneVal = `${originalPhone} ===DISC===PENDING`;

      const { error } = await supabase
        .from('applications')
        .update({ candidate_phone: updatedPhoneVal })
        .eq('id', appId);

      if (error) throw error;

      setJobApplicants(prev => prev.map(app => app.id === appId ? { ...app, candidate_phone: updatedPhoneVal } : app));
      alert('Teste de perfil DISC 5.0 solicitado com sucesso! O candidato já pode respondê-lo em seu painel.');
    } catch (err) {
      console.error('Erro ao solicitar teste DISC:', err);
      alert('Erro ao solicitar teste DISC.');
    }
  };"
